%java
// ---------------------------------------------------------------
// Load JFreeChart into the Zeppelin Java interpreter.
// After running 'mvn dependency:copy-dependencies -DoutputDirectory=libs'
// from the project root, update the path below with the full absolute
// path printed by run.sh (e.g. /home/youruser/creditcard_kmeans/libs/jfreechart-1.5.4.jar)
// ---------------------------------------------------------------
z.load("/home/YOUR_USERNAME/creditcard_kmeans/libs/jfreechart-1.5.4.jar");
System.out.println("JFreeChart loaded successfully.");

%java
import org.apache.hadoop.conf.Configuration;
import org.apache.hadoop.fs.FileSystem;
import org.apache.hadoop.fs.Path;
import org.apache.hadoop.fs.FSDataInputStream;
import org.apache.hadoop.fs.FSDataOutputStream;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.util.*;

// ---------------------------------------------------------------
// Replace YOUR_USERNAME with your actual Linux username.
// This is the output written by the K-Means MapReduce job.
// ---------------------------------------------------------------
String HDFS_INPUT = "/user/YOUR_USERNAME/project2/creditcard/output/final_clustered_points/part-m-00000";
String HDFS_OUT_BASE = "/user/YOUR_USERNAME/project2/creditcard/output";

String[] CLUSTER_LABELS = {"High Loyalty", "Mid Loyalty", "Low Loyalty"};
String[] FEATURE_NAMES  = {"Avg_Credit_Limit", "Total_Credit_Cards", "Bank_Visits", "Online_Visits", "Calls_Made"};

// Load Hadoop config from environment (picks up cluster settings automatically)
Configuration conf = new Configuration();
conf.addResource(new Path("/etc/hadoop/conf/core-site.xml"));
conf.addResource(new Path("/etc/hadoop/conf/hdfs-site.xml"));
FileSystem fs = FileSystem.get(conf);

FSDataInputStream in = fs.open(new Path(HDFS_INPUT));
BufferedReader reader = new BufferedReader(new InputStreamReader(in));

List<Integer>  clusterIds = new ArrayList<>();
List<double[]> points     = new ArrayList<>();

String line;
while ((line = reader.readLine()) != null) {
    line = line.trim();
    if (line.isEmpty()) continue;
    String[] parts = line.split(",");
    int clusterIdx = Integer.parseInt(parts[0]);
    double[] point = {
        Double.parseDouble(parts[1]),  // avg_credit_limit
        Double.parseDouble(parts[2]),  // total_credit_cards
        Double.parseDouble(parts[3]),  // bank_visits
        Double.parseDouble(parts[4]),  // online_visits
        Double.parseDouble(parts[5])   // calls_made
    };
    clusterIds.add(clusterIdx);
    points.add(point);
}
reader.close();

System.out.println("Loaded " + points.size() + " data points across 3 clusters.");
for (int c = 0; c < 3; c++) {
    final int cid = c;
    long cnt = clusterIds.stream().filter(x -> x == cid).count();
    System.out.println("  " + CLUSTER_LABELS[c] + ": " + cnt + " points");
}

%java
import org.jfree.chart.ChartFactory;
import org.jfree.chart.JFreeChart;
import org.jfree.chart.plot.XYPlot;
import org.jfree.chart.renderer.xy.XYDotRenderer;
import org.jfree.data.xy.XYSeries;
import org.jfree.data.xy.XYSeriesCollection;
import org.jfree.chart.ChartUtils;
import java.awt.Color;
import java.io.ByteArrayOutputStream;
import java.util.Base64;

Color[] COLORS = {
    new Color(231, 76,  60),
    new Color(46,  204, 113),
    new Color(52,  152, 219)
};

XYSeriesCollection dataset = new XYSeriesCollection();
XYSeries[] series = new XYSeries[3];
for (int c = 0; c < 3; c++) series[c] = new XYSeries(CLUSTER_LABELS[c]);

for (int i = 0; i < points.size(); i++) {
    double[] p = points.get(i);
    series[clusterIds.get(i)].add(p[0], p[1]);
}
for (XYSeries s : series) dataset.addSeries(s);

JFreeChart chart = ChartFactory.createScatterPlot(
    "K-Means (K=3): Avg Credit Limit vs Total Credit Cards",
    "Avg Credit Limit", "Total Credit Cards", dataset);

XYPlot plot = chart.getXYPlot();
XYDotRenderer r = new XYDotRenderer();
r.setDotWidth(5); r.setDotHeight(5);
for (int c = 0; c < 3; c++) r.setSeriesPaint(c, COLORS[c]);
plot.setRenderer(r);
plot.setBackgroundPaint(Color.WHITE);
plot.setDomainGridlinePaint(Color.LIGHT_GRAY);
plot.setRangeGridlinePaint(Color.LIGHT_GRAY);
chart.setBackgroundPaint(Color.WHITE);

ByteArrayOutputStream baos = new ByteArrayOutputStream();
ChartUtils.writeChartAsPNG(baos, chart, 900, 600);
byte[] bytes = baos.toByteArray();

// Write PNG back to HDFS
FSDataOutputStream out = fs.create(new Path(HDFS_OUT_BASE + "/viz_scatter_creditlimit_vs_cards.png"), true);
out.write(bytes); out.close();

// Display inline in Zeppelin
String b64 = Base64.getEncoder().encodeToString(bytes);
System.out.println("%html <img src='data:image/png;base64," + b64 + "' width='900'/>");
System.out.println("PNG written to HDFS: " + HDFS_OUT_BASE + "/viz_scatter_creditlimit_vs_cards.png");

