%java
import org.jfree.chart.JFreeChart;
import org.jfree.chart.axis.NumberAxis;
import org.jfree.chart.plot.XYPlot;
import org.jfree.chart.plot.ValueMarker;
import org.jfree.chart.renderer.xy.XYLineAndShapeRenderer;
import org.jfree.data.xy.XYSeries;
import org.jfree.data.xy.XYSeriesCollection;
import org.jfree.chart.ChartUtils;
import java.awt.*;
import java.io.ByteArrayOutputStream;
import java.util.*;
import java.util.Base64;

// Normalize each dimension to [0,1] so all axes are on same scale
double[] minVal = new double[5];
double[] maxVal = new double[5];
Arrays.fill(minVal,  Double.MAX_VALUE);
Arrays.fill(maxVal, -Double.MAX_VALUE);
for (double[] p : points) {
    for (int d = 0; d < 5; d++) {
        if (p[d] < minVal[d]) minVal[d] = p[d];
        if (p[d] > maxVal[d]) maxVal[d] = p[d];
    }
}

// One XYSeries per cluster; NaN gap separates individual customer lines
XYSeriesCollection dataset = new XYSeriesCollection();
XYSeries[] series = new XYSeries[3];
for (int c = 0; c < 3; c++) series[c] = new XYSeries(CLUSTER_LABELS[c], false, true);

for (int i = 0; i < points.size(); i++) {
    double[] p   = points.get(i);
    int      cid = clusterIds.get(i);
    for (int d = 0; d < 5; d++) {
        double norm = (maxVal[d] == minVal[d]) ? 0.0
            : (p[d] - minVal[d]) / (maxVal[d] - minVal[d]);
        series[cid].add((double) d, norm);
    }
    series[cid].add(5.0, Double.NaN);
}
for (XYSeries s : series) dataset.addSeries(s);

NumberAxis xAxis = new NumberAxis("Feature Dimension");
xAxis.setTickUnit(new org.jfree.chart.axis.NumberTickUnit(1));
xAxis.setRange(-0.3, 4.3);

NumberAxis yAxis = new NumberAxis("Normalized Value (0-1)");
yAxis.setRange(-0.05, 1.05);

XYLineAndShapeRenderer renderer = new XYLineAndShapeRenderer(true, false);
Color[] COLORS = {
    new Color(231, 76,  60,  100),
    new Color(46,  204, 113, 100),
    new Color(52,  152, 219, 100)
};
for (int c = 0; c < 3; c++) {
    renderer.setSeriesPaint(c, COLORS[c]);
    renderer.setSeriesStroke(c, new BasicStroke(1.2f));
}

XYPlot plot = new XYPlot(dataset, xAxis, yAxis, renderer);
plot.setBackgroundPaint(Color.WHITE);
plot.setDomainGridlinePaint(new Color(200, 200, 200));
plot.setRangeGridlinePaint(new Color(230, 230, 230));

for (int d = 0; d < 5; d++) {
    ValueMarker marker = new ValueMarker(d);
    marker.setPaint(new Color(80, 80, 80));
    marker.setStroke(new BasicStroke(1.5f));
    plot.addDomainMarker(marker);
}

JFreeChart chart = new JFreeChart(
    "Parallel Coordinates - Credit Card Customers (K=3)",
    JFreeChart.DEFAULT_TITLE_FONT, plot, true);
chart.setBackgroundPaint(Color.WHITE);

ByteArrayOutputStream baos = new ByteArrayOutputStream();
ChartUtils.writeChartAsPNG(baos, chart, 1000, 600);
byte[] bytes = baos.toByteArray();

FSDataOutputStream out = fs.create(new Path(HDFS_OUT_BASE + "/viz_parallel_coords.png"), true);
out.write(bytes); out.close();

String b64 = Base64.getEncoder().encodeToString(bytes);
System.out.println("%html");
System.out.println("<p><b>x-axis: 0=Avg_Credit_Limit | 1=Total_Credit_Cards | 2=Bank_Visits | 3=Online_Visits | 4=Calls_Made</b></p>");
System.out.println("<img src='data:image/png;base64," + b64 + "' width='1000'/>");
System.out.println("PNG written to HDFS: " + HDFS_OUT_BASE + "/viz_parallel_coords.png");

%java
int K = 3;
double[][] clusterSum   = new double[K][5];
int[]      clusterCount = new int[K];

for (int i = 0; i < points.size(); i++) {
    int    cid = clusterIds.get(i);
    double[] p = points.get(i);
    for (int d = 0; d < 5; d++) clusterSum[cid][d] += p[d];
    clusterCount[cid]++;
}

System.out.println("%table");
System.out.println("Cluster\tPoints\tAvg_Credit_Limit\tTotal_Credit_Cards\tBank_Visits\tOnline_Visits\tCalls_Made");
for (int c = 0; c < K; c++) {
    int cnt = clusterCount[c];
    if (cnt == 0) continue;
    System.out.printf("%s\t%d\t%.0f\t%.2f\t%.2f\t%.2f\t%.2f%n",
        CLUSTER_LABELS[c], cnt,
        clusterSum[c][0]/cnt, clusterSum[c][1]/cnt,
        clusterSum[c][2]/cnt, clusterSum[c][3]/cnt,
        clusterSum[c][4]/cnt);
}
